[asy]
pair A,B,C,W,X,Y,Z;
A=(-9,0); B=(0,12); C=(16,0);
W=(12A+25B)/37;
Z =(12C+25B)/37;
X=foot(W,A,C);
Y=foot(Z,A,C);
draw(A--B--C--cycle);
draw(X--W--Z--Y);
label("$A$",A,SW);
label("$B$",B,N);
label("$C$",C,E);
label("$W$",W,NW);
label("$X$",X,S);
label("$Y$",Y,S);
label("$Z$",Z,NE);
[/asy]

